package com.cabbooking.apigateway.controller;

import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;
import java.util.Arrays;
import java.util.List;

@RestController
@RequestMapping("/api/test")
@RequiredArgsConstructor
@Slf4j
public class TestController {

    @GetMapping("/postman-guide")
    public ResponseEntity<Map<String, Object>> getPostmanGuide() {
        Map<String, Object> response = new HashMap<>();

        response.put("message", "Complete Postman Testing Guide for API Gateway");
        response.put("gateway_port", "8088");
        response.put("auth_service_port", "8089 (or your auth service port)");

        // Step-by-step guide
        List<Map<String, Object>> steps = Arrays.asList(
            Map.of(
                "step", 1,
                "title", "Login to get JWT Token",
                "method", "POST",
                "url", "http://localhost:8088/api/auth/login",
                "headers", Map.of("Content-Type", "application/json"),
                "body", Map.of(
                    "email", "your-email@example.com",
                    "password", "your-password"
                ),
                "expected_response", "JWT token in response"
            ),
            Map.of(
                "step", 2,
                "title", "Test Public Endpoint (No Auth Required)",
                "method", "GET",
                "url", "http://localhost:8088/gateway/health",
                "headers", Map.of("Content-Type", "application/json"),
                "note", "This should work without Authorization header"
            ),
            Map.of(
                "step", 3,
                "title", "Test Protected Endpoint",
                "method", "GET",
                "url", "http://localhost:8088/api/locations",
                "headers", Map.of(
                    "Content-Type", "application/json",
                    "Authorization", "Bearer YOUR_JWT_TOKEN_HERE"
                ),
                "note", "Replace YOUR_JWT_TOKEN_HERE with actual token from step 1"
            )
        );

        // Common issues and solutions
        Map<String, String> troubleshooting = Map.of(
            "Invalid character in header", "Ensure JWT token is complete and not truncated. Copy full token from login response.",
            "Port 8086 vs 8088", "API Gateway runs on port 8088, not 8086. Update your requests.",
            "Missing Bearer prefix", "Authorization header must start with 'Bearer ' (note the space)",
            "Token truncated", "Ensure you copy the complete JWT token including all dots and characters",
            "Auth service down", "Make sure your auth service is running before testing protected endpoints"
        );

        response.put("steps", steps);
        response.put("troubleshooting", troubleshooting);

        return ResponseEntity.ok(response);
    }

    @GetMapping("/sample-urls")
    public ResponseEntity<Map<String, Object>> getSampleUrls() {
        Map<String, Object> response = new HashMap<>();

        // Public URLs (no authentication required)
        List<String> publicUrls = Arrays.asList(
            "GET http://localhost:8088/api/auth/login",
            "POST http://localhost:8088/api/auth/register",
            "GET http://localhost:8088/gateway/health",
            "GET http://localhost:8088/gateway/info",
            "GET http://localhost:8088/api/test/sample-urls",
            "GET http://localhost:8088/api/test/postman-guide"
        );

        // Protected URLs (authentication required)
        List<String> protectedUrls = Arrays.asList(
            "GET http://localhost:8088/api/users/profile",
            "GET http://localhost:8088/api/drivers/available",
            "POST http://localhost:8088/api/rides/book",
            "GET http://localhost:8088/api/locations",
            "POST http://localhost:8088/api/payments/process",
            "GET http://localhost:8088/api/ratings/user/123"
        );

        response.put("message", "API Gateway Sample URLs");
        response.put("correct_port", "8088 (not 8086)");
        response.put("public_urls", publicUrls);
        response.put("protected_urls", protectedUrls);

        return ResponseEntity.ok(response);
    }

    @GetMapping("/auth-status")
    public ResponseEntity<Map<String, String>> getAuthStatus() {
        Map<String, String> response = new HashMap<>();
        response.put("status", "SUCCESS - This endpoint requires authentication");
        response.put("message", "If you see this, your JWT token is valid and authentication is working");
        response.put("timestamp", java.time.LocalDateTime.now().toString());
        return ResponseEntity.ok(response);
    }
}

